INSERT INTO _content_posts VALUES ('posts/blog/visual-editor.md', 'Nuxt Studio 可视化编辑器幕后揭秘', '[{"name":"Baptiste Leproux","avatar":{"src":"https://avatars.githubusercontent.com/u/7290030?v=4"},"to":"https://x.com/_larbish","username":"larbish"},{"name":"Ferdinand Coumau","avatar":{"src":"https://avatars.githubusercontent.com/u/98885012?v=4"},"to":"https://x.com/CoumauFerdinand","username":"CoumauFerdinand"}]', '{"type":"minimark","value":[["h2",{"id":"简介"},["strong",{},"简介"]],["p",{},"Nuxt Studio 为开发者和内容撰写者提供了多功能的工作空间，允许他们在两个截然不同的编辑器之间进行选择，用于内容的创建和管理：Markdown 编辑器和可视化编辑器。"],["p",{},["img",{"alt":"从项目设置中选择你喜欢的编辑器","src":"/blog/favorite-editor.webp"}]],["p",{},"每个编辑器都有其独特的用途——有些用户习惯于 Markdown 编辑，而另一些则更喜欢非技术化的可视化方式。"],["p",{},"最终，",["strong",{},"这两种编辑器的最终输出都是 Markdown 语法"],"。"],["p",{},"本文将阐述可视化编辑器背后的技术流程，探讨它如何解析 Markdown、如何转换回 Markdown，以及为何这一过程有时可能会导致与原始内容的差异。"],["h2",{"id":"markdown-编辑器"},["strong",{},"Markdown 编辑器"]],["p",{},["img",{"alt":"在 Nuxt Studio 中直接编辑 Markdown","src":"/blog/markdown-editor.webp"}]],["p",{},"Nuxt Studio 中的 Markdown 编辑器允许你完全控制内容，可以直接编写 ",["a",{"href":"/docs/files/markdown"},"MDC"],"（增强型 Markdown 语法）。该语法支持直接将 Vue 组件集成到 Markdown 文件中，提供了更灵活的页面结构编排能力。"],["p",{},"当你在 Markdown 编辑器中保存文件时，内容会完全保持你所编写的形式，保留所有特定语法与格式。对于熟悉 Markdown 并希望精确控制内容布局和结构的用户来说，这款编辑器是理想选择。"],["h2",{"id":"可视化编辑器"},["strong",{},"可视化编辑器"]],["p",{},["img",{"alt":"在 Nuxt Studio 中使用可视化编辑器编辑你的内容","src":"/blog/visual-editor.webp"}]],["p",{},"可视化编辑器是一种基于 ",["a",{"href":"https://tiptap.dev/","rel":["nofollow"]},"TipTap"]," 和 ",["a",{"href":"https://prosemirror.net/","rel":["nofollow"]},"ProseMirror"]," 构建的所见即所得（WYSIWYG）工具，旨在屏蔽 Markdown 语法的复杂性，提供更直观的视觉编辑体验。对于不想直接处理原始 Markdown 代码的用户，这款编辑器尤其友好。"],["h3",{"id":"可视化编辑器如何处理文件"},["strong",{},"可视化编辑器如何处理文件"]],["p",{},"当你用可视化编辑器打开 Markdown 文件时，Nuxt Studio 首先会解析原始 Markdown 文件。借助 ",["a",{"href":"https://github.com/nuxt-modules/mdc","rel":["nofollow"]},"MDC 模块"],"，它生成一个抽象语法树（AST）。随后，该 AST 被转换为 TipTap 兼容的格式（TipTap AST），以便编辑器能够精准地可视化渲染文档内容。"],["p",{},"一旦可视化编辑器展示内容，用户便可通过直观的视觉方式进行更新。在幕后，编辑器持续地将 TipTap AST 转换回 MDC AST，再回转为 MDC 语法，确保内容始终保持 Markdown 格式。"],["h3",{"id":"为什么未修改内容时原始-markdown-文件会发生变化"},["strong",{},"为什么未修改内容时原始 Markdown 文件会发生变化"]],["p",{},["img",{"alt":"检测到自动 Markdown 解析时弹出提醒","src":"/blog/automatic-parsing-modal.webp"}]],["h4",{"id":"非关键性变化"},["strong",{},"非关键性变化"]],["p",{},"当可视化编辑器将视觉格式转换回 Markdown 时，会应用一套预设的 Markdown 标准解析算法。这些标准有时可能与原内容存在细微差别。这类变化通常影响不大，仅仅是 Markdown 语法的另一种有效写法，渲染后的网站表现应保持一致。"],["h4",{"id":"关键性变化"},["strong",{},"关键性变化"]],["p",{},"理想情况下，Markdown 的所有特性都能在可视化编辑器中有直接而准确的对应。我们已构建自定义 TipTap 扩展，以支持自定义 MDC 语法，例如 ",["a",{"href":"/docs/files/markdown#vue-components"},"Vue 组件"],"编辑或 ",["a",{"href":"/docs/files/markdown#front-matter"},"front-matter"]," 等。然而，在个别罕见的情况下，尤其是涉及复杂或不常见的 Markdown 元素时，可视化编辑器可能无法完全支持或正确解析这些元素。此时，编辑器可能会在解析过程中对这些元素进行近似处理、简化乃至省略。"],["p",{},"这类差异可能导致转换回 Markdown 时出现数据丢失或回退。虽然这种情况较少发生，但有可能影响内容的展示效果或功能。"],["p",{},"我们的主要目标是防止任何内容丢失，保持 Markdown 文件的完整性。如果你遇到从可视化编辑器切换回 Markdown 时出现不完美的情况，欢迎在我们的 Discord 服务器上反馈。你的反馈对我们改进和完善可视化编辑器极为重要，能确保满足所有用户的需求。"],["h2",{"id":"减少非预期变化的最佳实践"},["strong",{},"减少非预期变化的最佳实践"]],["p",{},"为避免丢失重要格式或内容，请遵循以下建议："],["ul",{},["li",{},["strong",{},"避免使用复杂的 HTML 结构"],"。由于 MDC 语法允许集成 Vue 组件，更推荐创建可复用组件，方便插入 Markdown 并在编辑器内编辑，而不是依赖复杂的 HTML 代码。"],["li",{},["strong",{},"保持编辑器的一致性"],"。尽可能选择最适合你需求的编辑器，并在整个页面编辑过程中保持使用同一编辑器。"],["li",{},["strong",{},"切换编辑器后务必检查变更"],"。切换编辑器后，务必在审核页面检查 Markdown 内容，并通过预览确保没有重要元素被修改。"]],["h2",{"id":"结语"},["strong",{},"结语"]],["p",{},"在 Nuxt Studio 中切换 Markdown 编辑器和可视化编辑器可以带来灵活的编辑体验，但需要注意背后的技术影响。"],["p",{},"理解可视化编辑器如何处理和转换 Markdown，有助于确保你所撰写的 Markdown 内容能准确地在可视化编辑器中显示，使非技术用户能够轻松编辑所有内容，而不破坏原始 Markdown 文件。"],["h3",{"id":""}]],"toc":{"title":"","searchDepth":2,"depth":2,"links":[{"id":"简介","depth":2,"text":"简介"},{"id":"markdown-编辑器","depth":2,"text":"Markdown 编辑器"},{"id":"可视化编辑器","depth":2,"text":"可视化编辑器","children":[{"id":"可视化编辑器如何处理文件","depth":3,"text":"可视化编辑器如何处理文件"},{"id":"为什么未修改内容时原始-markdown-文件会发生变化","depth":3,"text":"为什么未修改内容时原始 Markdown 文件会发生变化"}]},{"id":"减少非预期变化的最佳实践","depth":2,"text":"减少非预期变化的最佳实践"},{"id":"结语","depth":2,"text":"结语","children":[{"id":"","depth":3,"text":""}]}]}}', NULL, 'studio', '2024-09-04T00:00:00.000Z', '探索 Nuxt Studio 可视化编辑器的内部工作原理，以及它如何解析 Markdown 语法并重新生成内容。', false, 'md', '{"src":"/blog/visual-editor.webp"}', '{}', 'true', '/blog/visual-editor', '{"title":"Nuxt Studio 可视化编辑器幕后揭秘","description":"探索 Nuxt Studio 可视化编辑器的内部工作原理，以及它如何解析 Markdown 语法并重新生成内容。"}', 'blog/visual-editor', 'cdOeoQmj5Bmko9YZNNP2Cd1SF-Tw2lwD-TDSkqIFkLs'); -- cdOeoQmj5Bmko9YZNNP2Cd1SF-Tw2lwD-TDSkqIFkLs
INSERT INTO _content_posts VALUES ('posts/changelog/frontmatter-form.md', '可视化 Front-matter 编辑', '[{"name":"Baptiste Leproux","avatar":{"src":"https://avatars.githubusercontent.com/u/7290030?v=4"},"to":"https://x.com/_larbish"}]', '{"type":"minimark","value":[["warning",{},["p",{},"本文发布于 2025 年 1 月 6 日 ",["a",{"href":"https://github.com/nuxt/content","rel":["nofollow"]},"Content"]," 和 ",["a",{"href":"https://github.com/nuxtlabs/studio-module","rel":["nofollow"]},"Studio"]," 模块合并之前。因此，本文可能存在一些不一致之处。Studio 模块现已弃用，作为 Content 模块的可选功能提供。请参阅",["a",{"href":"/docs/getting-started"},"这份指南"],"了解如何启用。"]],["h2",{"id":"可视化-front-matter-编辑"},"可视化 Front-Matter 编辑"],["p",{},"现在您无需编写 ",["code",{},"YAML"]," 语法即可编辑 markdown front-matter。Nuxt Studio 会自动生成用户友好的表单，简化元数据编辑。"],["video",{":autoplay":"true",":controls":"true",":loop":"true","poster":"https://res.cloudinary.com/nuxt/video/upload/v1729157955/frontmatterform2_rmh58v.jpg","src":"https://res.cloudinary.com/nuxt/video/upload/v1729157955/frontmatterform2_rmh58v.mp4"}],["h2",{"id":"什么是-front-matter"},"什么是 Front-matter？"],["p",{},"Front-matter 是基于 Markdown 的 CMS 中用于为页面提供元数据（如描述、标题等）的约定。在 ",["a",{"href":"/docs/files/markdown#front-matter"},"Nuxt Content"]," 中，front-matter 使用的是 YAML 语法。"],["callout",{"icon":"i-ph-info","to":"/docs/files/markdown#front-matter"},["p",{},"关于 front-matter 语法的详细信息，请参阅 Nuxt Content 文档。"]],["h2",{"id":"我们非技术编辑器的最后一环"},"我们非技术编辑器的最后一环"],["p",{},"Nuxt Studio 从发布编辑器起就以非技术用户为设计核心。我们的目标是让每个人都能轻松编辑 markdown 和内容。"],["p",{},"自动生成 front-matter 表单是下一步的合理进展。通过摆脱 YAML 语法的复杂性，简化了非开发者的编辑流程，提供动态输入选项，如图片选择器、日期选择器、布尔切换等。此增强使我们实现了完全可视化且用户友好的内容管理体验。"],["h2",{"id":"扩展至所有-yaml-和-json-文件"},"扩展至所有 YAML 和 JSON 文件"],["p",{},"不久之后，表单生成功能将扩展至您在 Nuxt Studio 中编辑的所有 ",["code",{},"YAML"]," 和 ",["code",{},"JSON"]," 文件，让结构化数据的操作更为轻松便捷。"],["h2",{"id":"展望-nuxt-content-v3"},"展望 Nuxt Content v3"],["callout",{"icon":"i-ph-lightbulb"},["p",{},"本节内容仅为 ",["a",{"href":"https://github.com/nuxt/content/tree/v3","rel":["nofollow"]},"Nuxt Content v3"]," 的预告，我们将很快发布更详尽的博文。"]],["p",{},"我们正积极开发下一重大版本 Nuxt Content，这将带来显著的性能提升和新功能，进一步提升内容管理体验。"],["h3",{"id":"性能优化"},"性能优化"],["p",{},"Nuxt Content v2 的一大挑战是需要较大的包体积来存储所有内容文件，这在向边缘平台（如 ",["a",{"href":"https://hub.nuxt.com/","rel":["nofollow"]},"NuxtHub"],"）部署时造成了问题。"],["p",{},"为解决此问题，Nuxt Content v3 在生产环境中不再使用基于文件的存储方式，而是采用 SQL 数据库系统。此变更对用户透明。我们为开发模式、静态生成、服务器渲染及通过 NuxtHub 的边缘部署提供零配置支持。"],["h3",{"id":"引入-collections集合"},"引入 Collections（集合）"],["p",{},"Collections 是 Nuxt Content 项目中相关内容项的分组，帮助更高效地组织和管理大型数据集。"],["h4",{"id":"定义-collections"},"定义 Collections"],["p",{},"您可以在 ",["code",{},"content.config.ts"]," 文件中定义 collections，Nuxt Content 将用它配置数据库结构、类型工具及用于查找、解析和查询内容的方法。"],["h4",{"id":"collections-方案schema"},"Collections 方案（Schema）"],["p",{},"方案可确保 collections 内部的一致性，并改善 TypeScript 类型定义，增强与 Nuxt Content 工具的集成。"],["pre",{"className":"language-ts shiki shiki-themes material-theme-lighter material-theme material-theme-palenight","code":"import { defineCollection, z } from ''@nuxt/content''\n\n// 导出 collections\nexport const collections = {\n  // 使用 `defineCollection` 工具定义 collection\n  posts: defineCollection({\n    // 指定该 collection 中内容的类型\n    type: ''page'',\n    // 加载匹配此模式的所有文件\n    source: ''blog/**/*.md'',\n    // 为该 collection 定义自定义 schema\n    schema: z.object({\n      date: z.date(),\n      image: z.object({\n        src: z.string(),\n        alt: z.string()\n      }),\n      badge: z.object({\n        label: z.string(),\n        color: z.string()\n      })\n    })\n  }),\n}\n","filename":"content.config.ts","language":"ts","meta":"","style":""},["code",{"__ignoreMap":""},["span",{"class":"line","line":1},["span",{"class":"s7zQu"},"import"],["span",{"class":"sMK4o"}," {"],["span",{"class":"sTEyZ"}," defineCollection"],["span",{"class":"sMK4o"},","],["span",{"class":"sTEyZ"}," z"],["span",{"class":"sMK4o"}," }"],["span",{"class":"s7zQu"}," from"],["span",{"class":"sMK4o"}," ''"],["span",{"class":"sfazB"},"@nuxt/content"],["span",{"class":"sMK4o"},"''\n"]],["span",{"class":"li